from datetime import datetime

import jwt
from flask import current_app


def generate_token(user):
    private_key = '-----<KEY>'

    now = datetime.now()

    payload = {
        "uid": user['id'],
        "exp": int((now + 30).timestamp()), # token expires in 30 seconds from now
        "iat": now,                        # time the token was issued
    }

    return jwt.encode(payload, private_key, algorithm='RS256').decode('utf-8')


